parameters.jsonBody:
={
  "content": "Olá, tudo bem? Me chamo Julia Gabriela, vou fazer seu atendimento hoje.\nComo é seu nome?\n\nEntrei em contato porque trabalho na Convertix e ajudamos negócios locais a gerar mais conversas e agendamentos pelo WhatsApp usando campanhas direcionadas.\n\nMas antes de enviar um diagnóstico, queria entender seu cenário: hoje vocês dependem mais de indicação e Instagram ou já fazem algum tipo de anúncio pra captar novos clientes?",
  "message_type": "outgoing",
  "private": false,
  "content_type": "text"
}

parameters.jsCode:
const input = $json.body || $json;

const conversation = input.conversation || {};
const sender = input.sender || {};
const contentAttributes = input.content_attributes || {};

const content = String(input.content || '').trim();
const contentLower = content.toLowerCase();

const inboxName = String(input.inbox?.name || '').trim();

const inboxesPermitidas = [
  'ctxvendas0357',
  // 'ctxvendas'
];

const isInboxPermitida = inboxesPermitidas.includes(inboxName);

const botoesOptout = [
  'Bloquear contato / Sem interesse',
  'Não receber',
  'Sem interesse'
];

const botoesOptin = [
  'Ver detalhes',
  'Conversar no WhatsApp',
  'Confirmar',
  'Responder',
  'Conversar com a empresa',
  'Conversar com a equipe',
  'Confirmar recebimento'
];

const normalizar = (texto) =>
  String(texto || '').trim().toLowerCase();

const botoesOptoutLower = botoesOptout.map(normalizar);
const botoesOptinLower = botoesOptin.map(normalizar);

const botoesConhecidosLower = [
  ...botoesOptoutLower,
  ...botoesOptinLower
];

const inReplyToExternalId = String(
  contentAttributes.in_reply_to_external_id || ''
).trim();

const isReplyToWamid = inReplyToExternalId.startsWith('wamid.');

const isRespostaBotao =
  botoesConhecidosLower.includes(contentLower) &&
  isInboxPermitida &&
  isReplyToWamid;

let botaoAcao = null;

if (isRespostaBotao && botoesOptoutLower.includes(contentLower)) {
  botaoAcao = 'optout';
}

if (isRespostaBotao && botoesOptinLower.includes(contentLower)) {
  botaoAcao = 'optin';
}

const isOptin = botaoAcao === 'optin';
const isOptout = botaoAcao === 'optout';

const phoneNumber =
  sender.phone_number ||
  conversation?.messages?.[0]?.sender?.phone_number ||
  null;

return [
  {
    json: {
      conversation_id: conversation.id || input.conversation_id || null,
      contact_id: sender.id || conversation?.meta?.sender?.id || null,
      account_id: input.account?.id || conversation.account_id || null,

      inbox_id: input.inbox?.id || conversation.inbox_id || null,
      inbox_name: inboxName,

      sender_name: sender.name || conversation?.meta?.sender?.name || null,
      sender_phone: phoneNumber,
      sender_identifier: sender.identifier || null,

      message_type: input.message_type || null,
      content_type: input.content_type || null,
      file_type: input.attachments?.[0]?.file_type || null,
      audio_url: input.attachments?.[0]?.data_url || null,
      audio_duracao: input.attachments?.[0]?.audio_duration || null,

      message_id: input.id || null,
      source_id: input.source_id || null,
      message_created_at: input.created_at || null,
      message_updated_at: input.updated_at || null,
      message_content: content,
      message_content_lower: contentLower,

      is_resposta_botao: isRespostaBotao,
      botao_texto: isRespostaBotao ? content : null,
      botao_texto_lower: isRespostaBotao ? contentLower : null,
      botao_tipo: isRespostaBotao ? 'quick_reply_template' : null,

      botao_acao: botaoAcao,
      is_optin: isOptin,
      is_optout: isOptout,

      is_inbox_permitida: isInboxPermitida,
      is_reply_to_wamid: isReplyToWamid,
      in_reply_to: contentAttributes.in_reply_to || null,
      in_reply_to_external_id: contentAttributes.in_reply_to_external_id || null,

      conversation_status: conversation.status || null,
      conversation_can_reply: conversation.can_reply ?? null,
      conversation_labels: conversation.labels || [],
      unread_count: conversation.unread_count || 0,

      // body: input
    }
  }
];

